module asyn_fifo #(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

reg [WIDTH-1:0] ram [0:DEPTH-1];

reg [ADDR_WIDTH:0] wptr, rptr;
reg [ADDR_WIDTH:0] wptr_sync, rptr_sync;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
        wfull <= 0;
    end else if (winc && !wfull) begin
        ram[wptr[ADDR_WIDTH-1:0]] <= wdata;
        wptr <= wptr + 1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
        rempty <= 1;
        rdata <= 0;
    end else if (rinc && !rempty) begin
        rdata <= ram[rptr[ADDR_WIDTH-1:0]];
        rptr <= rptr + 1;
    end
end

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        rptr_sync <= 0;
    end else begin
        rptr_sync <= rptr;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        wptr_sync <= 0;
    end else begin
        wptr_sync <= wptr;
    end
end

always @* begin
    wfull = (wptr[ADDR_WIDTH-1:0] == rptr_sync[ADDR_WIDTH-1:0]) && (wptr[ADDR_WIDTH] != rptr_sync[ADDR_WIDTH]);
    rempty = (wptr_sync == rptr) || (wptr_sync == {~rptr[ADDR_WIDTH], rptr[ADDR_WIDTH-1:0]});
end

endmodule
